import{_ as n,o as e,c as h,ag as i}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"[Thiết kế Chi tiết] Module: Đặt chỗ & Thanh toán (Order State Machine)","description":"","frontmatter":{},"headers":[],"relativePath":"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/03-thiet-ke-chi-tiet.md","filePath":"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/03-thiet-ke-chi-tiet.md"}'),a={name:"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/03-thiet-ke-chi-tiet.md"};function o(l,t,r,c,d,g){return e(),h("div",null,[...t[0]||(t[0]=[i('<h1 id="thiet-ke-chi-tiet-module-đat-cho-thanh-toan-order-state-machine" tabindex="-1">[Thiết kế Chi tiết] Module: Đặt chỗ &amp; Thanh toán (Order State Machine) <a class="header-anchor" href="#thiet-ke-chi-tiet-module-đat-cho-thanh-toan-order-state-machine" aria-label="Permalink to &quot;[Thiết kế Chi tiết] Module: Đặt chỗ &amp; Thanh toán (Order State Machine)&quot;">​</a></h1><p>Tài liệu thiết kế chi tiết (Detailed Design Document) cho module Booking &amp; Payment, phục vụ việc xử lý logic đặt chỗ và thanh toán.</p><h2 id="_1-vong-đoi-đon-hang-order-state-machine" tabindex="-1">1. Vòng đời đơn hàng (Order State Machine) <a class="header-anchor" href="#_1-vong-đoi-đon-hang-order-state-machine" aria-label="Permalink to &quot;1. Vòng đời đơn hàng (Order State Machine)&quot;">​</a></h2><p>Hệ thống quản lý trạng thái đơn hàng (Order States) theo sơ đồ sau:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Trạng thái</th><th style="text-align:left;">Mã định danh</th><th style="text-align:left;">Mô tả</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Chờ thanh toán</strong></td><td style="text-align:left;"><code>PENDING</code></td><td style="text-align:left;">Khởi tạo đơn hàng, chờ phản hồi từ Cổng thanh toán</td></tr><tr><td style="text-align:left;"><strong>Đã thanh toán</strong></td><td style="text-align:left;"><code>PAID</code></td><td style="text-align:left;">Nhận tín hiệu thành công từ cổng thanh toán</td></tr><tr><td style="text-align:left;"><strong>Đã xác nhận</strong></td><td style="text-align:left;"><code>CONFIRMED</code></td><td style="text-align:left;">Hệ thống kiểm tra slot và xác nhận giữ chỗ thành công</td></tr><tr><td style="text-align:left;"><strong>Hoàn thành</strong></td><td style="text-align:left;"><code>COMPLETED</code></td><td style="text-align:left;">Sau khi ngày khởi hành tour đã kết thúc</td></tr><tr><td style="text-align:left;"><strong>Đã hủy</strong></td><td style="text-align:left;"><code>CANCELLED</code></td><td style="text-align:left;">User chủ động hủy hoặc hết hạn chờ thanh toán (Timeout)</td></tr><tr><td style="text-align:left;"><strong>Đã hoàn tiền</strong></td><td style="text-align:left;"><code>REFUNDED</code></td><td style="text-align:left;">Admin đã thực hiện hoàn trả tiền cho khách hàng</td></tr></tbody></table><h3 id="logic-chuyen-đoi-trang-thai-transitions" tabindex="-1">Logic Chuyển đổi Trạng thái (Transitions): <a class="header-anchor" href="#logic-chuyen-đoi-trang-thai-transitions" aria-label="Permalink to &quot;Logic Chuyển đổi Trạng thái (Transitions):&quot;">​</a></h3><ul><li><code>PENDING</code> -&gt; <code>PAID</code>: Nhận tín hiệu (Webhook/Callback) thành công.</li><li><code>PENDING</code> -&gt; <code>CANCELLED</code>: Sau 15 phút chưa thanh toán thành công.</li><li><code>PAID</code> -&gt; <code>REFUNDED</code>: Admin thực hiện hoàn tiền.</li></ul><h2 id="_2-đac-ta-xac-thuc-kiem-tra-validation-logic" tabindex="-1">2. Đặc tả Xác thực &amp; Kiểm tra (Validation Logic) <a class="header-anchor" href="#_2-đac-ta-xac-thuc-kiem-tra-validation-logic" aria-label="Permalink to &quot;2. Đặc tả Xác thực &amp; Kiểm tra (Validation Logic)&quot;">​</a></h2><h3 id="kiem-tra-slot-inventory-check" tabindex="-1">Kiểm tra Slot (Inventory Check): <a class="header-anchor" href="#kiem-tra-slot-inventory-check" aria-label="Permalink to &quot;Kiểm tra Slot (Inventory Check):&quot;">​</a></h3><ul><li>Trước khi chuyển từ Step 1 sang Step 2, hệ thống phải gọi API kiểm tra: <code>remaining_slots &gt;= requested_slots</code>.</li><li>Nếu không đủ slot, hiển thị thông báo: &quot;Rất tiếc, tour đã hết chỗ vào ngày này. Vui lòng chọn ngày khác.&quot;</li></ul><h3 id="quy-tac-voucher" tabindex="-1">Quy tắc Voucher: <a class="header-anchor" href="#quy-tac-voucher" aria-label="Permalink to &quot;Quy tắc Voucher:&quot;">​</a></h3><ul><li>Mỗi đơn hàng chỉ áp dụng tối đa 01 mã giảm giá.</li><li>Nếu mã đã hết lượt dùng hoặc hết hạn, hiển thị: &quot;Mã giảm giá không hợp lệ hoặc đã hết lượt sử dụng&quot;.</li></ul><h2 id="_3-xu-ly-loi-rui-ro-edge-cases" tabindex="-1">3. Xử lý Lỗi &amp; Rủi ro (Edge Cases) <a class="header-anchor" href="#_3-xu-ly-loi-rui-ro-edge-cases" aria-label="Permalink to &quot;3. Xử lý Lỗi &amp; Rủi ro (Edge Cases)&quot;">​</a></h2><ul><li><strong>Lỗi Dual-Payment</strong>: User nhấn thanh toán 2 lần -&gt; Backend kiểm tra trạng thái đơn hàng <code>!= PENDING</code> thì từ chối xử lý tiếp.</li><li><strong>Lỗi Call-back/Webhook</strong>: Cổng thanh toán gửi tín hiệu trễ. Khi nhận tín hiệu PAID cho đơn hàng đã CANCELLED (do hết hạn 15p), hệ thống phải đưa vào hàng đợi (Queue) để Admin xử lý hoàn tiền thủ công.</li></ul><h2 id="_4-đac-ta-ui-ux-chi-tiet" tabindex="-1">4. Đặc tả UI/UX Chi tiết <a class="header-anchor" href="#_4-đac-ta-ui-ux-chi-tiet" aria-label="Permalink to &quot;4. Đặc tả UI/UX Chi tiết&quot;">​</a></h2><ul><li><strong>Thanh tiến trình (Progress Bar)</strong>: Hiển thị 3 chấm (Info -&gt; Payment -&gt; Done) giúp user biết đang ở đâu.</li><li><strong>Tóm tắt đơn hàng (Sticky Summary)</strong>: Luôn hiển thị tổng tiền ở góc màn hình khi user cuộn trang.</li></ul><hr><p><em>Tài liệu chi tiết được định nghĩa bởi BA cho Sprint 4.</em></p>',18)])])}const m=n(a,[["render",o]]);export{u as __pageData,m as default};
